import { useState } from 'react';
import '../index.css';
import { useNavigate } from 'react-router-dom';
export function NavBar() {



  return (
    <header>
       <nav
      style={{
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        width: "100%",
        padding: "10px 40px",
        boxSizing: "border-box",
        background:"#af65c5",
        padding:"20px"
      }}
    >
       <div style={{ flex: 1, display: "flex", justifyContent: "center"}}>
   <input
          type="text"
          style={{
            width: "60%",
            height: "25px",
            fontSize: "18px",
            borderRadius: "8px",
            padding: "5px 10px",
          }}
        />


      </div>
      <div style={{ display: "flex", gap: "10px" }}>
        <span className="btnNav">Register</span>
        <span className="btnNav">Login</span>
      </div>
    </nav>
    </header>

  );
}
